#include<bits/stdc++.h>
using namespace std;
string dfs(string s,int x){
    if(x==s.size()){
        int ans=0;
        for(int i=0;i<s.size();i++){
            ans+=(s[i]-'0');
            ans*=10;
        }
        ans/=10;
        for(int i=2;i*i<=ans;i++) if(ans%i==0) return "-1";
        return s;
    }
    if(s[x]=='*'){
        for(int i=0;i<=9;i++){
            s[x]=i+'0';
            if(dfs(s,x+1)!="-1") return dfs(s,x+1);
            s[x]='*';
        }
        return "-1";
    }else{
        return dfs(s,x+1);
    }
}
int main(){
   int t;
    cin>>t;
    while(t--){
        string n;
        cin>>n;
        cout<<dfs(n,0)<<"\n";
    }
}
